mapper.select:
SELECT a.id, a.alarm_code, a.alarm_title, a.alarm_type, a.alarm_level, u.unit_name, sp.specialty_name, sy.system_name, mp.point_name AS measure_point_name, a.current_value, a.threshold_value, a.occur_time, a.confirmed, a.confirm_by, a.confirm_time, a.suppressed, a.classify_level FROM t_alarm_realtime a LEFT JOIN dim_unit u ON a.unit_id = u.id AND u.deleted = 0 LEFT JOIN dim_specialty sp ON a.specialty_id = sp.id AND sp.deleted = 0 LEFT JOIN dim_system sy ON a.system_id = sy.id AND sy.deleted = 0 LEFT JOIN dim_measure_point mp ON a.measure_point_id = mp.id AND mp.deleted = 0 WHERE a.deleted = 0
AND a.alarm_level = #{query.alarmLevel}
AND a.alarm_type = #{query.alarmType}
AND a.unit_id = #{query.unitId}
AND a.specialty_id = #{query.specialtyId}
AND a.confirmed = #{query.confirmed}
AND (a.alarm_title LIKE CONCAT('%', #{query.keyword}, '%') OR a.alarm_code LIKE CONCAT('%', #{query.keyword}, '%'))
ORDER BY a.occur_time DESC

SELECT COUNT(1)
FROM t_alarm_realtime
WHERE deleted = 0 AND suppressed = 0 AND alarm_level = #{alarmLevel}
